    g.fillStyle(0xd8c7aa, 1).fillRoundedRect(signX, signY, signW, signH, 4);

    // Regal wieder wie vorher, detailreich
    const shelfX = bodyX + 16, shelfY = bodyY + 54, shelfW = 68, shelfH = bodyH - 80;
