    g.fillStyle(0x5d4a2d, 1).fillRect(shelfX + 44, shelfY + 8, 9, 22);
    g.lineStyle(1, 0x3d2a1d, 1).lineBetween(shelfX + 48, shelfY + 8, shelfX + 48, shelfY + 30);
    // Regal 2
