    // Laterne
    const lx = bodyX + 98, ly = bodyY + 58;
    g.lineStyle(3, 0x2a2a2a, 1);
    g.lineBetween(lx - 22, ly - 16, lx, ly - 6);
    g.fillStyle(0x2a2a2a, 1).fillRect(lx - 6, ly - 6, 12, 4);
    g.fillStyle(0xffe2a8, 1).fillRoundedRect(lx - 10, ly - 4, 20, 28, 4);
