  _spawnPlanter(x, y, depth = 5) {
    const g = this.add.graphics().setDepth(depth);
    // Steintopf
    g.fillStyle(0x5a5a5a, 1).fillRoundedRect(x - 16, y, 32, 14, 4);
    g.fillStyle(0x3a3a3a, 1).fillRoundedRect(x - 14, y + 2, 28, 10, 3);
