} from 'https://www.gstatic.com/firebasejs/9.22.0/firebase-firestore.js';

// 1) Hol dir die Konfiguration aus deiner Firebase-Konsole (Projekt-Einstellungen → SDK-Snippet)
const firebaseConfig = {
